form:Form.form:Scripts:
		var CFG;
var TIT=null;
var T2T=null;

///////////////////////////////////////////////////////////////////////////////          
//EVENTOS
function OnLoad()
{                
	//Cargo la Configuracion
	CFG=new NomadXML(Ctrl("main").getResource("QRY_CFG"));

	//Modifico los Recursos
	ReplaceResource("QRY_IDS_OBJECT");
	ReplaceResource("QRY_IDS_PARENT");

	//Actualizo el Titulo
	if ((Ctrl("PAR"))&& (CFG.GetAttr("RESOURCE-PARENT")!="") && (Ctrl("PARENT").GetXValue()!=""))
	{
		if (TIT==null)
			TIT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_PARENT"), '<PARAM IDS="'+Ctrl("PARENT").GetXValue()+'"/>');

		if (TIT!=null) TIT=TIT.FirstChild();
		if (TIT!=null && TIT.GetAttr("descr")!="")
			Ctrl("PAR").SetXValue(" ("+TIT.GetAttr("descr")+")");
	}

	if ((Ctrl("OBJ"))&& (CFG.GetAttr("RESOURCE-OBJECT")!="") && (Ctrl("ID").GetXValue()!=""))
	{
		if (T2T==null)
			T2T=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_OBJECT"), '<PARAM IDS="'+Ctrl("ID").GetXValue()+'"/>');

		if (T2T!=null) T2T=T2T.FirstChild();
		if (T2T!=null && T2T.GetAttr("descr")!="")
			Ctrl("OBJ").SetXValue(" '"+T2T.GetAttr("descr")+"'");
	}        

	//Concateno los text
	var WikiTXT="";
	WikiTXT+=Ctrl("o_text").GetXValue();
	WikiTXT+=Ctrl("o_text2").GetXValue();
	WikiTXT+=Ctrl("o_text3").GetXValue();
	WikiTXT+=Ctrl("o_text4").GetXValue();
	Ctrl("WikiText").SetXValue(WikiTXT);
}

function ReplaceResource(recID)
{
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}

function SplitText()
{
	var TextS=new Array();
	var TextAll=Ctrl("WikiText").GetXValue(); 

	while (TextAll.length>0)
	{
		TextS.push(TextAll.substr(0,3500));
		TextAll=TextAll.substr(3500);
	}

	Ctrl("o_text" ).SetXValue(TextS[0]?TextS[0]:"");
	Ctrl("o_text2").SetXValue(TextS[1]?TextS[1]:"");
	Ctrl("o_text3").SetXValue(TextS[2]?TextS[2]:"");
	Ctrl("o_text4").SetXValue(TextS[3]?TextS[3]:"");
}
